import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"内布拉斯加家具城（Nebraska Furniture Mart）","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/内布拉斯加家具城.md","filePath":"03_companies/内布拉斯加家具城.md"}'),l={name:"03_companies/内布拉斯加家具城.md"};function i(o,t,h,n,u,s){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="内布拉斯加家具城-nebraska-furniture-mart" tabindex="-1">内布拉斯加家具城（Nebraska Furniture Mart） <a class="header-anchor" href="#内布拉斯加家具城-nebraska-furniture-mart" aria-label="Permalink to &quot;内布拉斯加家具城（Nebraska Furniture Mart）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>Nebraska Furniture Mart (NFM)</td></tr><tr><td>行业</td><td>家具/家居零售</td></tr><tr><td>成立年份</td><td>1937年</td></tr><tr><td>总部</td><td>内布拉斯加州奥马哈</td></tr><tr><td>伯克希尔持股</td><td>90%（1983年收购）</td></tr><tr><td>收购价格</td><td>约5,500万美元（多数股权）</td></tr></tbody></table><h2 id="核心业务" tabindex="-1">核心业务 <a class="header-anchor" href="#核心业务" aria-label="Permalink to &quot;核心业务&quot;">​</a></h2><p>美国最大的单店家居零售商，主营家具、地毯、电器等。单店年销售额超1亿美元，超过奥马哈所有竞争对手总和。</p><h2 id="收购故事" tabindex="-1">收购故事 <a class="header-anchor" href="#收购故事" aria-label="Permalink to &quot;收购故事&quot;">​</a></h2><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h3><ul><li>B夫人（Rose Blumkin）1937年用500美元创办</li><li>1983年单店年销售额已超1亿美元</li><li>巴菲特长期观察，了解其竞争力</li></ul><h3 id="收购条款" tabindex="-1">收购条款 <a class="header-anchor" href="#收购条款" aria-label="Permalink to &quot;收购条款&quot;">​</a></h3><ul><li>1983年收购90%股权</li><li>B夫人家族保留10%</li><li>关键年轻经理获得10%期权激励</li><li><strong>无审计、无库存盘点、无资产核实</strong></li></ul><h3 id="收购原因" tabindex="-1">收购原因 <a class="header-anchor" href="#收购原因" aria-label="Permalink to &quot;收购原因&quot;">​</a></h3><ol><li><strong>极致低成本运营</strong>：毛利率仅20%+，运营费用率16.5%</li><li><strong>采购优势</strong>：Louie Blumkin是全美最精明采购员</li><li><strong>管理传奇</strong>：B夫人90岁仍一周七天在卖场</li><li><strong>本地垄断</strong>：远超所有竞争对手效率</li></ol><h2 id="核心竞争优势" tabindex="-1">核心竞争优势 <a class="header-anchor" href="#核心竞争优势" aria-label="Permalink to &quot;核心竞争优势&quot;">​</a></h2><h3 id="_1-成本优势" tabindex="-1">1. 成本优势 <a class="header-anchor" href="#_1-成本优势" aria-label="Permalink to &quot;1. 成本优势&quot;">​</a></h3><ul><li>运营费用率仅16.5%（行业标杆Levitz为35.6%）</li><li>极低毛利率但有盈利能力</li><li>采购规模议价权强</li></ul><h3 id="_2-管理效率" tabindex="-1">2. 管理效率 <a class="header-anchor" href="#_2-管理效率" aria-label="Permalink to &quot;2. 管理效率&quot;">​</a></h3><ul><li>无复杂管理系统</li><li>家族式经营，决策快速</li><li>员工忠诚度高</li></ul><h3 id="_3-品牌效应" tabindex="-1">3. 品牌效应 <a class="header-anchor" href="#_3-品牌效应" aria-label="Permalink to &quot;3. 品牌效应&quot;">​</a></h3><ul><li>奥马哈本地绝对领先</li><li>口碑传播，获客成本低</li></ul><h2 id="管理团队" tabindex="-1">管理团队 <a class="header-anchor" href="#管理团队" aria-label="Permalink to &quot;管理团队&quot;">​</a></h2><h3 id="关键人物" tabindex="-1">关键人物 <a class="header-anchor" href="#关键人物" aria-label="Permalink to &quot;关键人物&quot;">​</a></h3><table tabindex="0"><thead><tr><th>姓名</th><th>职位</th><th>贡献</th></tr></thead><tbody><tr><td><a href="./../04_人物库/B夫人.html">B夫人（Rose Blumkin）</a></td><td>创始人/董事长</td><td>1937年创立，90+岁仍在工作</td></tr><tr><td><a href="./../04_人物库/Louie_Blumkin.html">Louie Blumkin</a></td><td>总裁</td><td>全美最精明采购员</td></tr><tr><td>Ron、Irv、Steve Blumkin</td><td>管理层</td><td>第三代家族成员</td></tr></tbody></table><h3 id="b夫人传奇" tabindex="-1">B夫人传奇 <a class="header-anchor" href="#b夫人传奇" aria-label="Permalink to &quot;B夫人传奇&quot;">​</a></h3><ul><li><strong>1893年</strong>：生于俄国，未受过正规教育</li><li><strong>1937年</strong>：500美元创办家具店</li><li><strong>1983年</strong>：90岁，一周七天在卖场卖地毯</li><li><strong>1984年</strong>：91岁仍每周工作七天</li><li><strong>1987年</strong>：94岁仍在工作</li><li><strong>格言</strong>：&quot;低价卖，说实话&quot;</li></ul><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><blockquote><p>&quot;我宁愿和灰熊摔跤，也不愿和B夫人竞争。&quot; —— 1984年股东信</p></blockquote><blockquote><p>&quot;假如我有大学商学院，我会让学生去NFM研究这门生意的所有方面。学生学到的会比任何商学院案例多得多。&quot; —— 1984年股东信</p></blockquote><blockquote><p>&quot;这个女人用500美元开始，现在每年卖1亿美元家具，从来没受过一天正式教育。&quot; —— 1984年股东信</p></blockquote><h2 id="财务表现-摘录" tabindex="-1">财务表现（摘录） <a class="header-anchor" href="#财务表现-摘录" aria-label="Permalink to &quot;财务表现（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>年销售额</th><th>增长率</th><th>备注</th></tr></thead><tbody><tr><td>1983</td><td>超1亿美元</td><td>-</td><td>美国最大单店家居销售</td></tr><tr><td>1984</td><td>1.15亿美元</td><td>-</td><td>毛利率20%+，费用率16.5%</td></tr><tr><td>1986</td><td>1.32亿美元</td><td>10.2%</td><td>持续增长</td></tr><tr><td>1987</td><td>1.426亿美元</td><td>8%</td><td>B夫人94岁仍在工作</td></tr></tbody></table><h2 id="与levitz对比-1984年" tabindex="-1">与Levitz对比（1984年） <a class="header-anchor" href="#与levitz对比-1984年" aria-label="Permalink to &quot;与Levitz对比（1984年）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>NFM</th><th>Levitz（行业标杆）</th></tr></thead><tbody><tr><td>年销售额</td><td>1.15亿美元</td><td>数十亿美元（连锁）</td></tr><tr><td>运营费用率</td><td>16.5%</td><td>35.6%</td></tr><tr><td>运营毛利率</td><td>约4%</td><td>约9%</td></tr><tr><td>单店效率</td><td>极高</td><td>相对较低</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./喜诗糖果.html">喜诗糖果</a> - 同为经典收购案例</li><li><a href="./水牛城新闻.html">水牛城新闻</a> - 同为控股子公司</li><li><a href="./../04_人物库/B夫人.html">B夫人</a> - 创始人传奇</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',38)])])}const q=a(l,[["render",i]]);export{c as __pageData,q as default};
